import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";

// Usamos la variable de entorno para la URL
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  /* =========================
      OBTENER DATOS
  ========================== */
  const obtenerProductos = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/productos`);
      setProductos(res.data);
    } catch (err) {
      console.error("❌ Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/clientes`);
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  /* =========================
      BUSCAR PRODUCTO
  ========================== */
  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);
    // Buscamos ignorando si el campo es 'Nombre' (MSSQL) o 'nombre' (Postgres)
    const producto = productos.find((p) =>
      (p.Nombre || p.nombre || "")
        .toLowerCase()
        .includes(texto.toLowerCase())
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  /* =========================
      AGREGAR AL CARRITO
  ========================== */
  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    // Normalizamos el stock y los IDs
    const stockActual = Number(productoSeleccionado.Stock ?? productoSeleccionado.stock ?? 0);
    const prodID = productoSeleccionado.ProductoID || productoSeleccionado.id;
    const precioUnitario = Number(productoSeleccionado.Precio || productoSeleccionado.precio);
    const nombreProd = productoSeleccionado.Nombre || productoSeleccionado.nombre;

    if (stockActual < cantidad) {
      setMensaje(`❌ Stock insuficiente. Disponible: ${stockActual}`);
      return;
    }

    const existente = carrito.find((p) => p.ProductID === prodID);

    if (existente) {
      setCarrito(
        carrito.map((p) =>
          p.ProductID === prodID
            ? { ...p, Cantidad: p.Cantidad + cantidad }
            : p
        )
      );
    } else {
      setCarrito([
        ...carrito,
        {
          ProductID: prodID,
          Nombre: nombreProd,
          Cantidad: cantidad,
          PrecioUnitario: precioUnitario,
        },
      ]);
    }

    // Resetear selección
    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
  };

  /* =========================
      CÁLCULOS
  ========================== */
  const calcularSubtotal = () =>
    carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);

  /* =========================
      REALIZAR VENTA
  ========================== */
  const realizarVenta = async () => {
    if (!clienteNombre.trim() || !clienteApellido.trim()) {
      setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
      return;
    }

    if (carrito.length === 0) {
      setMensaje("⚠️ El carrito está vacío.");
      return;
    }

    try {
      // Intentar encontrar si el cliente ya existe para pasar su ID
      let clienteExistente = clientes.find(
        (c) =>
          (c.Nombre || c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
          (c.Apellido || c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
      );

      const payload = {
        ClienteID: clienteExistente?.ClienteID || clienteExistente?.id || null,
        Nombre: clienteNombre,
        Apellido: clienteApellido,
        Telefono: clienteTelefono || "",
        EmisorNombre: "Sistema de Ventas Profesional",
        productos: carrito.map((p) => ({
          ProductID: p.ProductID,
          Cantidad: p.Cantidad
        }))
      };

      const res = await axios.post(`${API_URL}/api/ventas/registrar`, payload);

      setTicket(res.data);
      setMensaje("✅ Venta realizada con éxito.");
      setCarrito([]);
      setClienteNombre("");
      setClienteApellido("");
      setClienteTelefono("");
      obtenerProductos(); // Refrescar stock
      obtenerClientes();  // Refrescar lista por si se creó un cliente nuevo
    } catch (err) {
      const msgError = err.response?.data?.error || err.message;
      setMensaje(`❌ Error: ${msgError}`);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="text-center mb-4 fw-bold">Punto de Venta</h2>
      <div className="row">
        {/* PANEL IZQUIERDO: SELECCIÓN */}
        <div className="col-md-6">
          <div className="card shadow border-0 p-4 mb-4">
            <h5 className="fw-bold text-primary mb-3">1. Selección de Productos</h5>
            <input
              type="text"
              className="form-control mb-3"
              placeholder="Escriba el nombre del producto..."
              value={busquedaProducto}
              onChange={(e) => buscarProducto(e.target.value)}
              list="listaProductos"
            />
            <datalist id="listaProductos">
              {productos.map((p) => (
                <option key={p.ProductoID || p.id} value={p.Nombre || p.nombre} />
              ))}
            </datalist>

            {productoSeleccionado && (
              <div className="alert alert-secondary d-flex justify-content-between align-items-center">
                <div>
                  <strong>{productoSeleccionado.Nombre || productoSeleccionado.nombre}</strong><br/>
                  <small>Precio: ${productoSeleccionado.Precio || productoSeleccionado.precio} | Stock: {productoSeleccionado.Stock || productoSeleccionado.stock}</small>
                </div>
                <div className="d-flex gap-2 w-50">
                  <input
                    type="number"
                    className="form-control"
                    min="1"
                    value={cantidad}
                    onChange={(e) => setCantidad(Number(e.target.value))}
                  />
                  <button className="btn btn-primary" onClick={agregarAlCarrito}>➕</button>
                </div>
              </div>
            )}

            <h5 className="fw-bold text-primary mt-4 mb-3">2. Datos del Cliente</h5>
            <div className="row g-2">
                <div className="col-md-6">
                    <input className="form-control" placeholder="Nombre" value={clienteNombre} onChange={(e) => setClienteNombre(e.target.value)} />
                </div>
                <div className="col-md-6">
                    <input className="form-control" placeholder="Apellido" value={clienteApellido} onChange={(e) => setClienteApellido(e.target.value)} />
                </div>
                <div className="col-12">
                    <input className="form-control" placeholder="Teléfono (Opcional)" value={clienteTelefono} onChange={(e) => setClienteTelefono(e.target.value)} />
                </div>
            </div>

            {mensaje && <div className={`alert mt-3 ${mensaje.includes('✅') ? 'alert-success' : 'alert-danger'}`}>{mensaje}</div>}
          </div>
        </div>

        {/* PANEL DERECHO: CARRITO */}
        <div className="col-md-6">
          <div className="card shadow border-0 p-4 mb-4 bg-light">
            <h5 className="fw-bold text-dark mb-3">🛒 Carrito de Compras</h5>
            <div className="table-responsive" style={{minHeight: "200px"}}>
                {carrito.length === 0 ? (
                <p className="text-center text-muted mt-5">No hay productos agregados.</p>
                ) : (
                <table className="table table-hover">
                    <thead>
                        <tr>
                            <th>Producto</th>
                            <th>Cant.</th>
                            <th>Subtotal</th>
                        </tr>
                    </thead>
                    <tbody>
                    {carrito.map((p, i) => (
                        <tr key={i}>
                        <td>{p.Nombre}</td>
                        <td>{p.Cantidad}</td>
                        <td className="text-end">${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                        </tr>
                    ))}
                    </tbody>
                </table>
                )}
            </div>

            <hr />
            <div className="d-flex justify-content-between fs-5">
                <span>Subtotal:</span>
                <span>${calcularSubtotal().toFixed(2)}</span>
            </div>
            <div className="d-flex justify-content-between fs-5 text-muted">
                <span>IVA (12%):</span>
                <span>${(calcularSubtotal() * 0.12).toFixed(2)}</span>
            </div>
            <div className="d-flex justify-content-between fs-4 fw-bold text-success mt-2">
                <span>Total:</span>
                <span>${(calcularSubtotal() * 1.12).toFixed(2)}</span>
            </div>

            <button
              className="btn btn-success btn-lg w-100 mt-4 shadow"
              onClick={realizarVenta}
              disabled={carrito.length === 0}
            >
              💰 Confirmar y Facturar
            </button>
          </div>
        </div>
      </div>

      {/* COMPONENTE TICKET */}
      {ticket && <TicketVenta ticket={ticket} setTicket={setTicket} />}
    </div>
  );
}
